'use strict';

var Linter = require( 'eslint' ).Linter;
var rule = require( './../lib' );

var linter = new Linter();

var code = [
	'var v = foo();',
	'// returns             \'beep\'',
	'',
	'console.log( bar() );',
	'// => \'boop\''
].join( '\n' );

linter.defineRule( 'doctest-annotation-spacing', rule );

var result = linter.verify( code, {
	'rules': {
		'doctest-annotation-spacing': 'error'
	}
});
console.log( result );
